// Shared lock variable
volatile int lock = 0;

// Test and Set atomic operation
int test_and_set(volatile int *addr) {
    int old;
    __asm__ __volatile__(
        "xchg %0, %1"  // xchg is atomic on x86
        : "=r" (old), "=m" (*addr)
        : "0" (1), "m" (*addr)
        : "memory"
    );
    return old;
}

// Acquire lock
void lock_acquire(volatile int *lock) {
    while (test_and_set(lock) != 0);  // spin until acquired
}

// Release lock
void lock_release(volatile int *lock) {
    *lock = 0;
}

// Usage in critical section
void critical_section() {
    lock_acquire(&lock);
    // critical section code here
    lock_release(&lock);
}

ALGORITHM PetersonsAlgorithm
SHARED VARIABLES
  turn: 0..1          // whose turn to enter
  flag[2]: BOOLEAN    // process ready to enter CS
  lock: BOOLEAN       // hardware lock for atomicity

PROCESS P[i] where i is 0 or 1
BEGIN
  j ← 1 - i  // the other process

  flag[i] ← TRUE          // I want to enter
  turn ← j                // give priority to other

  // Wait while: other wants in AND it's other's turn
  WHILE (flag[j] = TRUE) AND (turn = j) DO
    // Busy wait or check hardware lock
    IF lock = 0 THEN       // Hardware atomic test-and-set
      lock ← 1
      EXIT LOOP
    END IF
  END WHILE

  // CRITICAL SECTION
  // ... access shared resources ...

  flag[i] ← FALSE         // I'm done

  // REMAINDER SECTION
END

// HARDWARE ASSUMPTIONS REQUIRED:
// 1. Atomic read-modify-write for lock variable
// 2. Sequential memory access ordering (no reorderings)
// 3. Cache coherence (all processors see same values)

import java.util.concurrent.atomic.AtomicReference;

class LockFreeStack<T> {
    // Node definition for stack elements
    private static class Node<T> {
        T value;
        Node<T> next;
        Node(T val) { this.value = val; }
    }

    // Atomic reference to top of stack
    private AtomicReference<Node<T>> top = new AtomicReference<>(null);

    // Push operation using CAS
    public void push(T value) {
        Node<T> newNode = new Node<>(value);
        Node<T> oldTop;
        do {
            oldTop = top.get();
            newNode.next = oldTop;
            // Try to CAS: if top still equals oldTop, update to newNode
        } while (!top.compareAndSet(oldTop, newNode));
        // If CAS fails, another thread modified top; retry with new oldTop
    }

    // Pop operation using CAS
    public T pop() {
        Node<T> oldTop;
        Node<T> newTop;
        do {
            oldTop = top.get();
            if (oldTop == null) return null;  // Empty stack
            newTop = oldTop.next;
            // Try to CAS: if top still equals oldTop, update to newTop
        } while (!top.compareAndSet(oldTop, newTop));
        // If CAS fails, another thread modified top; retry
        return oldTop.value;
    }

    // Check if empty
    public boolean isEmpty() {
        return top.get() == null;
    }
}

// Usage
LockFreeStack<Integer> stack = new LockFreeStack<>();
stack.push(10);
stack.push(20);
System.out.println(stack.pop());  // Prints: 20
